package com.google.gson.protobuf;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.protobuf.Descriptors.EnumValueDescriptor;
import com.google.protobuf.DescriptorProtos.EnumValueOptions;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.lang.reflect.Method;
import java.util.Collections;
import java.util.Set;

public class ProtoTypeAdapterTest {

    private ProtoTypeAdapter adapterNameSerialization;
    private ProtoTypeAdapter adapterNumberSerialization;

    private EnumValueDescriptor enumValueDescriptorMock;
    private EnumValueOptions enumValueOptionsMock;

    enum EnumSerialization {
        NAME,
        NUMBER
    }

    @BeforeEach
    public void setUp() throws Exception {
        // Create instance of ProtoTypeAdapter with enumSerialization = NAME
        adapterNameSerialization = createProtoTypeAdapter(EnumSerialization.NAME);
        // Create instance of ProtoTypeAdapter with enumSerialization = NUMBER
        adapterNumberSerialization = createProtoTypeAdapter(EnumSerialization.NUMBER);

        // Mock EnumValueDescriptor
        enumValueDescriptorMock = mock(EnumValueDescriptor.class);
        enumValueOptionsMock = mock(EnumValueOptions.class);

        // Mock getOptions() to return enumValueOptionsMock
        when(enumValueDescriptorMock.getOptions()).thenReturn(enumValueOptionsMock);
    }

    private ProtoTypeAdapter createProtoTypeAdapter(EnumSerialization enumSerialization) throws Exception {
        // Use reflection to get ProtoTypeAdapter constructor
        Class<?> clazz = ProtoTypeAdapter.class;
        var constructor = clazz.getDeclaredConstructor(
                EnumSerialization.class,
                com.google.common.base.CaseFormat.class,
                com.google.common.base.CaseFormat.class,
                Set.class,
                Set.class);
        constructor.setAccessible(true);
        return (ProtoTypeAdapter) constructor.newInstance(
                enumSerialization,
                com.google.common.base.CaseFormat.LOWER_UNDERSCORE,
                com.google.common.base.CaseFormat.LOWER_CAMEL,
                Collections.emptySet(),
                Collections.emptySet());
    }

    @Test
    public void testGetEnumValue_NameSerialization_CustomSerializedValue() throws Exception {
        // Arrange
        String defaultName = "ENUM_NAME";
        when(enumValueDescriptorMock.getName()).thenReturn(defaultName);

        // Spy adapter to mock private getCustSerializedEnumValue method
        ProtoTypeAdapter spyAdapter = Mockito.spy(adapterNameSerialization);

        String customValue = "custom_serialized_value";

        // Mock private method getCustSerializedEnumValue(EnumValueOptions,String) via reflection
        Method getCustSerializedEnumValueMethod = ProtoTypeAdapter.class.getDeclaredMethod(
                "getCustSerializedEnumValue",
                EnumValueOptions.class,
                String.class);
        getCustSerializedEnumValueMethod.setAccessible(true);

        // Use doReturn().when(spyAdapter).<method>(args) pattern with reflection
        // Since Mockito cannot mock private method directly with doReturn().when(),
        // we use doAnswer with reflection invoke.

        Mockito.doAnswer(invocation -> {
            // Return customValue regardless of parameters
            return customValue;
        }).when(spyAdapter).getClass()
                .getDeclaredMethod("getCustSerializedEnumValue", EnumValueOptions.class, String.class)
                .invoke(spyAdapter, enumValueOptionsMock, defaultName);

        // The above won't compile because invoke returns Object, not a mockito stubbable method.
        // Instead, we do the following:

        // Use Mockito's spy and doReturn with reflection via Whitebox or use PowerMockito.
        // Since PowerMockito is not allowed, use spy and override method by subclassing.

        // Alternative: Use reflection to set the method accessible and override by creating a subclass.

        // So create a subclass of ProtoTypeAdapter that overrides getCustSerializedEnumValue

        class ProtoTypeAdapterSubclass extends ProtoTypeAdapter {
            ProtoTypeAdapterSubclass(EnumSerialization enumSerialization) throws Exception {
                super(enumSerialization,
                        com.google.common.base.CaseFormat.LOWER_UNDERSCORE,
                        com.google.common.base.CaseFormat.LOWER_CAMEL,
                        Collections.emptySet(),
                        Collections.emptySet());
            }

            @Override
            protected String getCustSerializedEnumValue(EnumValueOptions options, String defaultValue) {
                return customValue;
            }
        }

        ProtoTypeAdapterSubclass adapterSubclass = new ProtoTypeAdapterSubclass(EnumSerialization.NAME);

        // Act
        Method getEnumValueMethod = ProtoTypeAdapter.class.getDeclaredMethod("getEnumValue", EnumValueDescriptor.class);
        getEnumValueMethod.setAccessible(true);
        Object result = getEnumValueMethod.invoke(adapterSubclass, enumValueDescriptorMock);

        // Assert
        assertEquals(customValue, result);
    }

    @Test
    public void testGetEnumValue_NumberSerialization_ReturnsNumber() throws Exception {
        // Arrange
        int number = 123;
        when(enumValueDescriptorMock.getNumber()).thenReturn(number);

        // Act
        Method getEnumValueMethod = ProtoTypeAdapter.class.getDeclaredMethod("getEnumValue", EnumValueDescriptor.class);
        getEnumValueMethod.setAccessible(true);
        Object result = getEnumValueMethod.invoke(adapterNumberSerialization, enumValueDescriptorMock);

        // Assert
        assertEquals(number, result);
    }
}
